record_types.code:
type gsl_interp is record
   c_type : access constant gsl_interp_type;
   xmin   : aliased double;
   xmax   : aliased double;
   size   : aliased size_t;
   state  : System.Address;
end record;

type gsl_interp_accel is record
   cache      : aliased size_t;
   miss_count : aliased size_t;
   hit_count  : aliased size_t;
end record;

type gsl_interp_type is record
   name : Interfaces.C.Strings
     .chars_ptr;
   min_size : aliased unsigned;
   alloc    : access function
     (arg1 : size_t)
      return System.Address;
   init : access function
     (arg1 : System.Address; arg2 : double_array; arg3 : double_array;
      arg4 : size_t) return int;
   eval : access function
     (arg1 : System.Address; arg2 : double_array; arg3 : double_array;
      arg4 : size_t; arg5 : double; arg6 : access gsl_interp_accel;
      arg7 : double_array)
      return int;
   eval_deriv : access function
     (arg1 : System.Address; arg2 : double_array; arg3 : double_array;
      arg4 : size_t; arg5 : double; arg6 : access gsl_interp_accel;
      arg7 : double_array)
      return int;
   eval_deriv2 : access function
     (arg1 : System.Address; arg2 : double_array; arg3 : double_array;
      arg4 : size_t; arg5 : double; arg6 : access gsl_interp_accel;
      arg7 : double_array)
      return int;
   eval_integ : access function
     (arg1 : System.Address; arg2 : double_array; arg3 : double_array;
      arg4 : size_t; arg5 : access gsl_interp_accel; arg6 : double;
      arg7 : double; arg8 : double_array)
      return int;
   free : access procedure
     (arg1 : System.Address);
end record;

